const data = $input.first().json;
const webhook = $node['Webhook: Section Regen'].json.body;

try {
  const fullResponse = data.content[0].text;

  let htmlContent = fullResponse;
  let sectionUpdate = null;

  const separatorIndex = fullResponse.indexOf('---SECTION_UPDATE---');
  if (separatorIndex !== -1) {
    htmlContent = fullResponse.substring(0, separatorIndex).trim();
    const updateJson = fullResponse.substring(separatorIndex + 19).trim();
    try {
      sectionUpdate = JSON.parse(updateJson.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim());
    } catch(e) { sectionUpdate = null; }
  }

  htmlContent = htmlContent.replace(/^```html\n?/g, '').replace(/\n?```$/g, '').trim();

  return [{
    json: {
      generation_id: webhook.generation_id,
      html_content: htmlContent,
      section_update: sectionUpdate,
      section_index: webhook.section_index
    }
  }];
} catch (e) {
  return [{
    json: {
      generation_id: webhook.generation_id,
      error: e.message
    }
  }];
}
